// scripts/apply-lyric-variants-migration.mjs
// Applies drizzle/0007_lyric_variants.sql to Supabase via postgres-js.
//
// Why a custom apply script instead of `drizzle-kit migrate`?
//   - The journal/snapshot pair under drizzle/meta/ is regenerated by
//     `pnpm drizzle-kit generate`, which compares the live schema.ts
//     against the latest snapshot. Running it here would also include
//     any other unrelated schema drift, which we explicitly want to avoid.
//   - This script applies ONLY the lyricVariants migration in a single
//     transaction. Idempotent via IF NOT EXISTS guards.
//
// Usage:
//   node scripts/apply-lyric-variants-migration.mjs --dry-run
//   node scripts/apply-lyric-variants-migration.mjs

import postgres from "postgres";
import dotenv from "dotenv";

dotenv.config();

const DB_URL =
  process.env.SUPABASE_SESSION_POOLER_STRING ??
  process.env.SUPABASE_DIRECT_CONNECTION_STRING ??
  process.env.DATABASE_URL;
if (!DB_URL) {
  console.error("Set SUPABASE_SESSION_POOLER_STRING in .env");
  process.exit(1);
}

const DRY_RUN = process.argv.includes("--dry-run") || process.argv.includes("--dry");

const STATEMENTS = [
  `ALTER TABLE "songs" ADD COLUMN IF NOT EXISTS "lyricVariants" jsonb`,
];

if (DRY_RUN) {
  console.log("Dry-run. Statements that would execute:");
  for (const s of STATEMENTS) {
    console.log("  " + s.replace(/\s+/g, " ").trim());
  }
  process.exit(0);
}

const sql = postgres(DB_URL, { max: 2 });

try {
  console.log("Applying lyric_variants migration in a single transaction ...");
  await sql.begin(async (tx) => {
    for (const s of STATEMENTS) {
      await tx.unsafe(s);
    }
  });
  console.log("Migration applied.");
} catch (err) {
  console.error("Migration failed:", err.message);
  process.exitCode = 1;
} finally {
  await sql.end();
}
